import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';

// Dashboard cha code direct ithech taka (Temporary)
const Home = () => (
  <div className="container py-5 text-center">
    <h1 className="display-4 fw-bold text-primary">Apni Manzil Dashboard</h1>
    <p className="lead">Site chalu ahe! Ata apan ek-ek components fix karuya.</p>
    <div className="row mt-4">
        <div className="col-md-4"><div className="card p-4 shadow-sm">Courier Service</div></div>
        <div className="col-md-4"><div className="card p-4 shadow-sm">Transport Service</div></div>
        <div className="col-md-4"><div className="card p-4 shadow-sm">Business MSME</div></div>
    </div>
  </div>
);

function App() {
  return (
    <Router>
      <nav className="navbar navbar-dark bg-primary px-4">
        <Link className="navbar-brand fw-bold" to="/">APNI MANZIL</Link>
      </nav>
      <Routes>
        <Route path="/" element={<Home />} />
      </Routes>
    </Router>
  );
}

export default App;
